import{_ as a,o as l,c as e,a0 as o}from"./chunks/framework.CSGB4SNl.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/java-hot200-day08.md","filePath":"java/eight-legged essay/java-hot200-day08.md"}'),s={name:"java/eight-legged essay/java-hot200-day08.md"};function t(r,i,n,d,h,c){return l(),e("div",null,[...i[0]||(i[0]=[o('<h4 id="tcp-ip的四层模型是什么" tabindex="-1">TCP/IP的四层模型是什么 <a class="header-anchor" href="#tcp-ip的四层模型是什么" aria-label="Permalink to &quot;TCP/IP的四层模型是什么&quot;">​</a></h4><ol><li>网络接口层：以太网/WIFI-底层网络传输服务</li><li>网络层：IP之类的-主机间通信</li><li>传输层：TCP/UDP-为应用层提供端到端的通信</li><li>应用层：HTTP/HTTPS\\FTP-为应用程序提供服务</li></ol><h4 id="mybatis的缓存" tabindex="-1">mybatis的缓存 <a class="header-anchor" href="#mybatis的缓存" aria-label="Permalink to &quot;mybatis的缓存&quot;">​</a></h4><ol><li>一级缓存默认开启，每个sqlseesion内共享，二级缓存跨sqlseesion共享</li><li>在同一个sqlseesion中执行相同的sql语句和参数，之间从缓存中拿结果，缓存key由命名空间 + sql语句 + 参数组成，commit、回滚、增删改操作都会把缓存清掉</li><li>二级缓存是Mapper层的，需要写cache标签才行，每个命名空间下共享缓存结果，二级缓存查不到的话从一级缓存查，查不到再去数据库查，查到依次回填缓存结果，增删改操作会把缓存清掉，支持对接redis这样的第三方缓存实现</li></ol><h4 id="spring-boot是什么" tabindex="-1">Spring Boot是什么 <a class="header-anchor" href="#spring-boot是什么" aria-label="Permalink to &quot;Spring Boot是什么&quot;">​</a></h4><ol><li>就是spring + 自动配置</li><li>起步依赖：自带一系列依赖</li><li>自动配置：约定大于配置，比如你引入了mysql的依赖包，他就猜到你要连接数据库就自动帮你写好了连接池配置，除非你自己去改</li><li>内置tomcat服务器</li><li>核心注解：@SpringBootApplication、@EnableAutoConfiguration</li><li>自动配置原理：就是去读取application.yml之类的，判断要加载哪些Bean</li></ol><h4 id="创建线程的几种方式" tabindex="-1">创建线程的几种方式 <a class="header-anchor" href="#创建线程的几种方式" aria-label="Permalink to &quot;创建线程的几种方式&quot;">​</a></h4><ol><li>实现Runable接口，实现run方法，将Runable对象传给Thread构造函数，执行start</li><li>直接继承Thread类，重写run方法，但是java支持单继承，继承了这个类就没法继承其他类，所以现在用的比较少</li><li>new FutrueTask，传入具体执行内容，再new一个Thread，将task作为参数传入，执行start方法</li><li>使用线程池-ExecutorService，好处是避免线程的重复创建和销毁的开销</li><li>使用CompletableFuture，java8后引入的，能够很好的组合各异步任务，处理任务之间的依赖关系</li><li>io密集用虚拟线程，cpu密集用线程池，纯计算任务虚拟线程不断切换开销大，不如传统线程池绑定cpu跑，另外虚拟线程和synchronized搭配会有问题</li></ol><h4 id="redis跳表的实现原理" tabindex="-1">Redis跳表的实现原理 <a class="header-anchor" href="#redis跳表的实现原理" aria-label="Permalink to &quot;Redis跳表的实现原理&quot;">​</a></h4><ol><li>本质上是一个多层链表，上层链表存底层链表的子集，底层链表存具体元素</li><li>查找的时候一层一层，遇到比目标值大的就往下走一层,只到找到或确定没有</li><li>修改也是按照查找先找到目标位置，然后随机决定新节点要建几层索引，redis用25%概率往上加一层</li><li>删除就是找到节点，把这个节点在每一层的前后指针都接上，然后执行普通的链表删除，只是要多层操作</li></ol><h4 id="redis性能瓶颈时如何处理" tabindex="-1">Redis性能瓶颈时如何处理 <a class="header-anchor" href="#redis性能瓶颈时如何处理" aria-label="Permalink to &quot;Redis性能瓶颈时如何处理&quot;">​</a></h4><ol><li>垂直扩容：单机资源用满就加内存，读写分离：写走主节点，读走从节点，适合读多写少的场景</li><li>redis分片，将1万多个槽位分散到多个主节点上，也能横向分散写压力</li><li>多级缓存，加入如Caffire这样的本地缓存，先从本地查，再查redis</li><li>本地缓存时间设置短一点，也可以用发布订阅来向本地缓存广播redis数据变更进行清除</li></ol><h4 id="cookie、session、token有什么区别" tabindex="-1">Cookie、Session、Token有什么区别 <a class="header-anchor" href="#cookie、session、token有什么区别" aria-label="Permalink to &quot;Cookie、Session、Token有什么区别&quot;">​</a></h4><ol><li>Cookie是存在客户端的，无状态，且每次请求都会带上，适用于记录用户行为偏好等临时存储</li><li>Session是存在服务端的包含用户信息有状态，客户端生成一个sessionid，适用于传统web应用</li><li>Token是一个凭证，无状态，服务端不用存储状态，拓展性好，跨域性强也就是单点登录</li><li>经常Session和Token混用，Token做无状态认证，成功后在服务端生成一个Session记录用户信息</li><li>Token放在哪比较安全这个各有优劣，loaclStore的话持久性强，但是会被XSS读取到，sessionStore的话安全稍强一点但是不夸标签页，且不持久化，Cookie的话就需要去防护CSRF攻击因为Cookie请求都会携带</li><li>Token被盗的话一般是没法主动让他失效得过期，但是可以配合黑名单来过滤掉</li></ol><h4 id="分库分表的几种策略" tabindex="-1">分库分表的几种策略 <a class="header-anchor" href="#分库分表的几种策略" aria-label="Permalink to &quot;分库分表的几种策略&quot;">​</a></h4><ol><li>水平分表：按照数据来分表，如user_0、user_1、user_2</li><li>垂直分表：按照列字段来拆分，常用字段存一个表，不常用字段存另一个表，比如user_info里面有用户名、手机号等，另一个user_detail存用户住址之类的</li><li>水平分库：也是如分表那样，按照数据进行拆分，012这样</li><li>垂直分库：按照模块来拆分，比如用户表存一个库，订单表存一个库这样</li><li>缺点需要跨表跨库处理事务之类的，维护成本大大增加</li></ol><h4 id="mybatis中的-和-有什么区别" tabindex="-1">Mybatis中的#{}和${}有什么区别 <a class="header-anchor" href="#mybatis中的-和-有什么区别" aria-label="Permalink to &quot;Mybatis中的#{}和${}有什么区别&quot;">​</a></h4><ol><li>#{}走的是预编译，会替换成jdbc中的?占位符，由于是预编译sql语句已经提前编译好了，所以无论如何传进去的都是当作值处理，天然防住了sql注入</li><li>${}就是存粹的字符串替换，会被解析成sql语句，导致sql注入问题 OR 1 = 1就会把整张表数据都查出来</li></ol><h4 id="final关键字是否能保证变量的可见性" tabindex="-1">final关键字是否能保证变量的可见性 <a class="header-anchor" href="#final关键字是否能保证变量的可见性" aria-label="Permalink to &quot;final关键字是否能保证变量的可见性&quot;">​</a></h4><ol><li>不能，final关键字修饰的变量与构造函数强绑定，只能确保构造函数初始化后能够被其它线程访问到正确的值，这个是final的可见性和平时说的可见性不一样，那种可见性只有valatite才能保证</li></ol>',20)])])}const k=a(s,[["render",t]]);export{b as __pageData,k as default};
